/**
 * 创建一个防抖（debounce）函数
 *
 * @param {Function} fn       - 需要防抖的原始函数
 * @param {number}   delay    - 延迟时间（毫秒）
 * @param {Object}   options  - 可选配置
 * @param {boolean}  options.leading  - 是否在延迟开始前立即执行一次（默认 false）
 * @param {boolean}  options.trailing - 是否在延迟结束后执行最后一次（默认 true）
 * @returns {Function} 经过防抖包装的函数，附带 .cancel() 和 .flush() 方法
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;

  let timerId = null;       // setTimeout 句柄
  let lastArgs = null;      // 最后一次调用的参数
  let lastThis = null;      // 最后一次调用的 this 上下文
  let leadingInvoked = false; // 是否已经在 leading 阶段执行过

  // 核心逻辑：在 delay 结束后执行 fn
  const invoke = () => {
    if (trailing && lastArgs) {
      fn.apply(lastThis, lastArgs);
    }
    // 重置状态
    timerId = null;
    lastArgs = null;
    lastThis = null;
    leadingInvoked = false;
  };

  const debounced = function (...args) {
    lastArgs = args;
    lastThis = this;

    // 如果已有定时器，清除它（防抖的核心：重新计时）
    if (timerId !== null) {
      clearTimeout(timerId);
    }

    // leading 模式：如果没有正在进行的定时器且尚未在 leading 阶段执行，立即执行
    if (leading && !leadingInvoked && !timerId) {
      fn.apply(this, args);
      leadingInvoked = true;
    }

    // 设置新的定时器（trailing 模式下，这会在 delay 后执行最后一次调用）
    timerId = setTimeout(invoke, delay);
  };

  /**
   * 取消当前未执行的防抖调用
   */
  debounced.cancel = () => {
    if (timerId !== null) {
      clearTimeout(timerId);
    }
    timerId = null;
    lastArgs = null;
    lastThis = null;
    leadingInvoked = false;
  };

  /**
   * 立即执行待处理的调用，并清除定时器
   */
  debounced.flush = () => {
    if (timerId !== null) {
      clearTimeout(timerId);
      invoke();
    }
  };

  return debounced;
}
```

---

## 使用示例

```javascript
// 基本用法：搜索输入防抖
const searchInput = document.getElementById('search');
const handleSearch = debounce(
  (event) => console.log('搜索：', event.target.value),
  300
);
searchInput.addEventListener('input', handleSearch);

// leading 模式：节流阀用途，先执行一次，然后防抖后续
const save = debounce(
  () => console.log('保存中...'),
  2000,
  { leading: true, trailing: false }
);

// 手动取消
const log = debounce(() => console.log('hi'), 1000);
log();
log.cancel(); // 不会再输出

// 手动立即执行
const send = debounce((msg) => console.log('发送：', msg), 5000);
send('hello');
send.flush(); // 立即打印，无需等 5 秒
```

---

## 关键要点

| 概念 | 说明 |
|------|------|
| **防抖 vs 节流** | 防抖是「延迟合并」——频繁触发时只执行最后一次；节流是「频率限制」——固定时间间隔只执行一次 |
| **leading** | 是否在触发一开始就执行（类似节流的立即执行版） |
| **trailing** | 是否在停止触发后执行最后一次（默认 `true`） |
| **cancel()** | 清除定时器，放弃待执行的调用 |
| **flush()** | 立即执行待处理的调用，常用于组件卸载前确保最后状态被提交 |

> 纯函数 + 无外部依赖，浏览器 / Node.js 通用。

